package com.parkflow.mall.gateway.vision;
import java.io.IOException;import org.springframework.beans.factory.annotation.Value;import org.springframework.core.io.ByteArrayResource;import org.springframework.http.*;import org.springframework.stereotype.Service;import org.springframework.util.LinkedMultiValueMap;import org.springframework.util.MultiValueMap;import org.springframework.web.client.*;
@Service public class VisionServiceProxy {private final RestTemplate rest;private final String base;public VisionServiceProxy(RestTemplate rest,@Value("${gateway.vision-base-url}")String base){this.rest=rest;this.base=base;}
 public ResponseEntity<String> ocr(String authorization,org.springframework.web.multipart.MultipartFile image,String cameraId,String gateId)throws IOException{HttpHeaders h=new HttpHeaders();if(authorization!=null)h.set(HttpHeaders.AUTHORIZATION,authorization);h.setContentType(MediaType.MULTIPART_FORM_DATA);MultiValueMap<String,Object> body=new LinkedMultiValueMap<>();ByteArrayResource resource=new ByteArrayResource(image.getBytes()){public String getFilename(){return image.getOriginalFilename();}};HttpHeaders imageHeaders=new HttpHeaders();imageHeaders.setContentType(MediaType.parseMediaType(image.getContentType()==null?MediaType.APPLICATION_OCTET_STREAM_VALUE:image.getContentType()));body.add("image",new HttpEntity<>(resource,imageHeaders));if(cameraId!=null)body.add("cameraId",cameraId);if(gateId!=null)body.add("gateId",gateId);try{var r=rest.exchange(base+"/api/vision/ocr/plate",HttpMethod.POST,new HttpEntity<>(body,h),String.class);return ResponseEntity.status(r.getStatusCode()).contentType(MediaType.APPLICATION_JSON).body(r.getBody());}catch(HttpStatusCodeException e){return ResponseEntity.status(e.getStatusCode()).contentType(MediaType.APPLICATION_JSON).body(e.getResponseBodyAsString());}catch(ResourceAccessException e){return ResponseEntity.status(HttpStatus.BAD_GATEWAY).contentType(MediaType.APPLICATION_JSON).body("{\"error\":\"vision-service unavailable\"}");}}
}
